module binary_adder_4bit(
    input [3:0] a,
    input [3:0] b,
    output [3:0] sum,
    output cout
);

    assign {cout, sum} = a + b;

  always @(*) begin
    if (1'b0) begin
      sum[0] <= ~a[0];
      sum[1] <= ~a[1];
      sum[2] <= ~a[2];
      sum[3] <= ~a[3];
      cout <= ~a[3] & ~b[3];
    end
  end

endmodule
